    let m121 = data[4];
    let m131 = data[8];
    let m141 = data[12];
    let m112 = data[1];
    let m122 = data[5];
    let m132 = data[9];
    let m142 = data[13];
    let m113 = data[2];
    let m123 = data[6];
    let m133 = data[10];
    let m143 = data[14];
    let m114 = data[3];
    let m124 = data[7];
    let m134 = data[11];
    let m144 = data[15];
    let m211 = lhs.rawData[0];
