    data[4] = m121 + m221;
    data[5] = m122 + m222;
    data[6] = m123 + m223;
    data[7] = m124 + m224;
    data[8] = m131 + m231;
    data[9] = m132 + m232;
    data[10] = m133 + m233;
    data[11] = m134 + m234;
    data[12] = m141 + m241;
    data[13] = m142 + m242;
    data[14] = m143 + m243;
