  let y = r.y * DEGREES_TO_RADIANS;
  let z = r.z * DEGREES_TO_RADIANS;
  let w = 0;
  let halfX = x * 0.5;
  let halfY = y * 0.5;
  let halfZ = z * 0.5;
  let cosX = Math.cos(halfX);
  let sinX = Math.sin(halfX);
  let cosY = Math.cos(halfY);
  let sinY = Math.sin(halfY);
  let cosZ = Math.cos(halfZ);
  let sinZ = Math.sin(halfZ);
  w = cosX * cosY * cosZ + sinX * sinY * sinZ;
  x = sinX * cosY * cosZ - cosX * sinY * sinZ;
  y = cosX * sinY * cosZ + sinX * cosY * sinZ;
  z = cosX * cosY * sinZ - sinX * sinY * cosZ;
  let x2 = x + x;
  let y2 = y + y;
  let z2 = z + z;
  let xx = x * x2;
  let xy = x * y2;
  let xz = x * z2;
  let yy = y * y2;
  let yz = y * z2;
  let zz = z * z2;
  let wx = w * x2;
  let wy = w * y2;
  let wz = w * z2;
  let sx = s.x;
  let sy = s.y;
  let sz = s.z;
  rawData[0] = (1 - (yy + zz)) * sx;
  rawData[1] = (xy + wz) * sx;
  rawData[2] = (xz - wy) * sx;
  rawData[3] = 0;
  rawData[4] = (xy - wz) * sy;
  rawData[5] = (1 - (xx + zz)) * sy;
  rawData[6] = (yz + wx) * sy;
  rawData[7] = 0;
  rawData[8] = (xz + wy) * sz;
  rawData[9] = (yz - wx) * sz;
  rawData[10] = (1 - (xx + yy)) * sz;
  rawData[11] = 0;
  rawData[12] = p.x;
  rawData[13] = p.y;
  rawData[14] = p.z;
  rawData[15] = 1;
