    this.planes[3].y = vpm[7] - vpm[5];
    this.planes[3].z = vpm[11] - vpm[9];
    this.planes[3].w = vpm[15] - vpm[13];
    t = Math.sqrt(this.planes[3].x * this.planes[3].x + this.planes[3].y * this.planes[3].y + this.planes[3].z * this.planes[3].z);
