    for (let i = 0; i < this.randomSeedCount; i++) {
      let angle = Math.PI * 2 * i / this.randomSeedCount;
      let v = new Vector3(Math.sin(angle), Math.cos(angle), this.directionDistance).normalize(1);
      this.arroundPositions.push(v);
    }
