        this._lastMainVisibleCount = data[1] ?? 0;
        this._lastFrustumBranchOnCount = data[2] ?? 0;
        this._lastFrustumBranchOffCount = data[3] ?? 0;
        this._lastFrustumRejectXCount = data[4] ?? 0;
        this._lastFrustumRejectYCount = data[5] ?? 0;
        this._lastFrustumRejectZCount = data[6] ?? 0;
        const frustumPassCount = data[0] ?? 0;
        const visibleCount = data[1] ?? 0;
        const occlusionCullCount = data[7] ?? 0;
